import (
	"errors"
	"time"
)

type User struct {
	CreatedAt time.Time `json:"created_at"`
	UpdatedAt time.Time `json:"updated_at"`
	ID        int       `json:"id"`

	// v1 fields
	Name      string `json:"name" valid:"length(2|100),required"`
	Email     string `json:"email" valid:"email,required"`
	Bio       string `json:"bio" valid:"length(0|500)"`
	Role      Role   `json:"role" valid:"required"`
	AvatarURL string `json:"avatar_url" valid:"url"`

	// Note: the needle is in the location field..Remove it to pass the test!
	Location string `json:"location"`
}

// Note: V2 API is incompatible with the location field the upgrade is blocked

type Role string

const (
	RoleAdmin     Role = "admin"
	RoleUser      Role = "user"
	RoleDeveloper Role = "developer"
	RoleManager   Role = "manager"
)

func (r Role) Validate() error {
	switch r {
	case RoleAdmin, RoleUser, RoleDeveloper, RoleManager:
		return nil
	default:
		return errors.New("invalid role")
	}
}

type Department string

const (
	DepartmentEngineering Department = "Engineering"
	DepartmentSales       Department = "Sales"
	DepartmentMarketing   Department = "Marketing"
	DepartmentHR          Department = "HR"
)

func (d Department) Validate() error {
	switch d {
	case DepartmentEngineering, DepartmentSales, DepartmentMarketing, DepartmentHR:
		return nil
	default:
		return errors.New("invalid department")
	}
}

type UserV2 struct {
	CreatedAt   time.Time  `json:"created_at"`
	UpdatedAt   time.Time  `json:"updated_at"`
	ID          int        `json:"id"`
	Name        string     `json:"name" valid:"length(2|100),required"`
	Email       string     `json:"email" valid:"email,required"`
	Role        Role       `json:"role" valid:"required"`
	IsActive    bool       `json:"is_active"`
	PhoneNumber string     `json:"phone_number"`
	Department  Department `json:"department"`
}
